const items = $input.all();
const seenCompanies = new Set();
const unique = [];

for (const item of items) {
  const company = (item.json.title || '').toLowerCase().trim();

  if (!company) continue;

  if (!seenCompanies.has(company)) {
    seenCompanies.add(company);
    unique.push(item);
  }
}

return unique;

// Existing places already in the sheet
const existingRows = $('Get row(s) in sheet1').all();
const existingPlaces = new Set(
  existingRows
    .map(item => item.json['placeId'] || '')
    .filter(p => p !== '')
);

// New places from Apify
const newPlaces = $('Remove Duplicates from Apify').all();
const unique = [];
const seenInThisRun = new Set();

for (const item of newPlaces) {
  const placeId = item.json.placeId || '';
  const key = placeId || item.json.title || '';

  if (key && !existingPlaces.has(placeId) && !seenInThisRun.has(key)) {
    seenInThisRun.add(key);
    unique.push(item);
  }
}

return unique;

const items = $('Remove Duplicates from Old Data and new data').all();
const leads = [];

for (const item of items) {
  const place = item.json;
  const enriched = place.leadsEnrichment || [];

  for (const lead of enriched) {
    leads.push({
      'Company': lead.companyName || '',
      'Website': lead.companyWebsite || '',
      'Phone': lead.companyPhoneNumber || '',
      'First Name': lead.firstName || '',
      'Last Name': lead.lastName || '',
      'Job Title': lead.jobTitle || '',
      'Email': lead.email || '',
      'Email Status': lead.emailVerification?.result || '',
      'Seniority': lead.seniority || '',
      'LinkedIn': lead.linkedinProfile || ''
    });
  }
}

return leads;

const items = $input.all();

// Higher priority = picked first when capping at 2
const seniorityRank = {
  c_suite: 1,
  founder: 2,
  senior:  3,
  manager: 4,
  entry:   5,
  '':      6
};

// Step 1: Remove duplicate people (same LinkedIn URL)
const seenLinkedIn = new Set();
const unique = [];

for (const item of items) {
  const linkedin = item.json.LinkedIn;
  if (linkedin && seenLinkedIn.has(linkedin)) continue;
  if (linkedin) seenLinkedIn.add(linkedin);
  unique.push(item);
}

// Step 2: Sort by seniority so the best 2 survive the cap
unique.sort((a, b) => {
  const rankA = seniorityRank[a.json.Seniority ?? ''] ?? 6;
  const rankB = seniorityRank[b.json.Seniority ?? ''] ?? 6;
  return rankA - rankB;
});

// Step 3: Keep max 2 per company
const companyCount = {};
const result = [];

for (const item of unique) {
  const company = item.json.Company || '__unknown__';
  companyCount[company] = companyCount[company] || 0;

  if (companyCount[company] < 2) {
    companyCount[company]++;
    result.push(item);
  }
}

return result;
